import React from 'react';
import { useNavigate } from 'react-router-dom';

const Dashboard = () => {
    const navigate = useNavigate();

    const handleLogout = () => {
        localStorage.clear();
        navigate('/');
    };

    return (
        <div style={{ padding: '20px' }}>
            <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <h1>SuperAdmin Dashboard</h1>
                <button onClick={handleLogout} style={{ height: '30px' }}>Logout</button>
            </div>
            <hr />
            <h3>Master Screens</h3>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(3, 1fr)', gap: '10px' }}>
                <button style={{ padding: '20px' }}>Department Master</button>
                <button style={{ padding: '20px' }}>Programme Master</button>
                <button style={{ padding: '20px' }}>Block Master</button>
                <button style={{ padding: '20px' }}>Room Master</button>
                <button style={{ padding: '20px' }}>User Screen</button>
            </div>
        </div>
    );
};

export default Dashboard;
